/// Write plain data bytes to a SPI device (not necessarily SPI EEPROM/flash).
#[derive(Debug, StructOpt)]
pub struct SpiRawWrite {
    #[structopt(short, long, help = "Hex data bytes to write.")]
    hexdata: String,
