use opentitanlib::uart::console::{ExitStatus, UartConsole};
use opentitanlib::util::parse_int::ParseInt;

#[derive(Debug, Parser)]
struct Opts {
    #[command(flatten)]
    init: InitializeTest,

    #[arg(
        long, value_parser = humantime::parse_duration,
        default_value = "5s",
        help = "Bootstrap detection timeout",
